ORDER BY r.role_id ASC ORDER BY r.role_id DESC ORDER BY r.role_nm ASC ORDER BY r.role_nm DESC ORDER BY r.reg_date ASC ORDER BY r.reg_date DESC ORDER BY r.reg_date DESC
